import os
import requests
import json
import re
import math
import hashlib
import threading
from datetime import datetime
from typing import List, Union, Generator, Iterator
from pydantic import BaseModel, Field

try:
    from bs4 import BeautifulSoup
except ImportError:
    BeautifulSoup = None

try:
    from pptx import Presentation
    from pptx.util import Inches, Pt
    from pptx.dml.color import RGBColor
    from pptx.enum.text import PP_ALIGN
    import io, base64

    PPTX_AVAILABLE = True
except ImportError:
    PPTX_AVAILABLE = False


class MemoryManager:
    MEMORY_DIR = "/app/backend/data/memories"
    MAX_MEMORIES = 1000
    TOP_K = 5
    EMBED_MODEL = "bge-m3"
    # Минимальный порог сходства — записи ниже этого не показываются
    MIN_SIMILARITY = 0.7

    def __init__(self, api_key: str, base_url: str):
        self.api_key = api_key
        self.base_url = base_url.rstrip("/")
        try:
            os.makedirs(self.MEMORY_DIR, exist_ok=True)
        except Exception:
            # Если /app/backend/data не существует (локальный запуск не в Docker),
            # фолбечим в /tmp/gpthub_memories
            self.MEMORY_DIR = "/tmp/gpthub_memories"
            os.makedirs(self.MEMORY_DIR, exist_ok=True)

    # ─── Cosine similarity без numpy ───────────────────────────────
    @staticmethod
    def _cosine(a: list, b: list) -> float:
        if not a or not b or len(a) != len(b):
            return 0.0
        dot = sum(x * y for x, y in zip(a, b))
        norm_a = math.sqrt(sum(x * x for x in a))
        norm_b = math.sqrt(sum(x * x for x in b))
        if norm_a == 0 or norm_b == 0:
            return 0.0
        return dot / (norm_a * norm_b)

    # ─── Эмбеддинг текста через bge-m3 ────────────────────────────
    def _embed(self, text: str) -> list:
        try:
            res = requests.post(
                f"{self.base_url}/embeddings",
                headers={
                    "Authorization": f"Bearer {self.api_key}",
                    "Content-Type": "application/json",
                },
                json={"model": self.EMBED_MODEL, "input": text[:2000]},
                timeout=15,
            )
            return res.json()["data"][0]["embedding"]
        except Exception:
            return []

    # ─── Хранение ──────────────────────────────────────────────────
    def _path(self, user_id: str) -> str:
        safe = hashlib.md5(user_id.encode()).hexdigest()
        return os.path.join(self.MEMORY_DIR, f"{safe}.json")

    def _load(self, user_id: str) -> dict:
        path = self._path(user_id)
        if not os.path.exists(path):
            return {"user_id": user_id, "memories": []}
        try:
            with open(path, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            return {"user_id": user_id, "memories": []}

    def _save(self, user_id: str, data: dict):
        try:
            with open(self._path(user_id), "w", encoding="utf-8") as f:
                json.dump(data, f, ensure_ascii=False, indent=2)
        except Exception:
            pass

    # ─── Добавить воспоминание ─────────────────────────────────────
    def add(self, user_id: str, mem_type: str, content: str) -> bool:
        """
        Добавляет воспоминание, если похожего ещё нет (дедупликация по cosine > 0.92).
        Возвращает True если добавлено, False если пропущено как дубликат.
        """
        content = content.strip()
        if not content or len(content) < 10:
            return False

        data = self._load(user_id)
        memories = data["memories"]

        embedding = self._embed(content)

        # Дедупликация
        for m in memories:
            if self._cosine(m.get("embedding", []), embedding) > 0.92:
                return False

        memories.append(
            {
                "id": hashlib.md5(
                    f"{user_id}{content}{datetime.now().isoformat()}".encode()
                ).hexdigest()[:12],
                "type": mem_type,
                "content": content,
                "embedding": embedding,
                "created_at": datetime.now().isoformat(),
            }
        )

        # FIFO — удаляем старые если превышаем лимит
        if len(memories) > self.MAX_MEMORIES:
            memories.sort(key=lambda x: x.get("created_at", ""))
            memories = memories[-self.MAX_MEMORIES :]

        data["memories"] = memories
        self._save(user_id, data)
        return True

    # ─── Семантический поиск ───────────────────────────────────────
    def retrieve(self, user_id: str, query: str, top_k: int = None) -> list:
        """Возвращает top_k наиболее релевантных воспоминаний для запроса."""
        top_k = top_k or self.TOP_K
        data = self._load(user_id)
        memories = data.get("memories", [])
        if not memories:
            return []

        query_emb = self._embed(query)
        if not query_emb:
            # Если эмбеддинг недоступен — возвращаем последние N записей
            return [m["content"] for m in memories[-top_k:]]

        scored = []
        for m in memories:
            sim = self._cosine(m.get("embedding", []), query_emb)
            if sim >= self.MIN_SIMILARITY:
                scored.append((sim, m))

        scored.sort(key=lambda x: x[0], reverse=True)
        return [m["content"] for _, m in scored[:top_k]]

    # ─── Извлечение фактов из диалога ─────────────────────────────
    def extract_from_exchange(
        self,
        user_id: str,
        api_key: str,
        base_url: str,
        router_model: str,
        user_message: str,
        assistant_message: str,
    ):
        """
        Вызывает LLM чтобы извлечь факты/резюме из обмена и сохраняет их.
        Запускается в отдельном потоке чтобы не блокировать стриминг.
        """
        if not user_message or not assistant_message:
            return
        # Не извлекаем из коротких обменов (< 30 символов ответа) и системных сообщений
        if len(assistant_message) < 30:
            return

        prompt = (
            "Проанализируй диалог ниже и извлеки ТОЛЬКО объективно полезные факты.\n"
            "Верни JSON без markdown-обёртки в формате:\n"
            '{"facts": ["факт 1", "факт 2"], "summaries": ["резюме задачи 1"]}\n\n'
            "Правила:\n"
            '- В "facts": личные данные пользователя (имя, профессия, язык, страна, предпочтения, '
            "навыки, проекты над которыми работает, используемые технологии/инструменты).\n"
            '- В "summaries": кратко (1 предложение) что было сделано/решено, только если задача была '
            "нетривиальной (написан код, создана презентация, найдена информация и т.д.).\n"
            "- Если фактов нет — верни пустые списки.\n"
            "- Не добавляй очевидное (например 'пользователь написал сообщение').\n"
            "- Факты формулируй от третьего лица: 'Пользователь работает с Python'.\n\n"
            f"Пользователь: {user_message[:500]}\n\n"
            f"Ассистент: {assistant_message[:800]}\n\n"
            "JSON:"
        )

        def _run():
            try:
                res = requests.post(
                    f"{base_url}/chat/completions",
                    headers={"Authorization": f"Bearer {api_key}"},
                    json={
                        "model": router_model,  # лёгкая модель для экономии
                        "messages": [{"role": "user", "content": prompt}],
                        "max_tokens": 400,
                        "temperature": 0.1,
                    },
                    timeout=20,
                )
                raw = res.json()["choices"][0]["message"]["content"]
                raw = re.sub(r"```json\s*", "", raw)
                raw = re.sub(r"```\s*", "", raw)
                extracted = json.loads(raw.strip())

                for fact in extracted.get("facts", []):
                    self.add(user_id, "fact", fact)
                for summary in extracted.get("summaries", []):
                    self.add(user_id, "summary", summary)
            except Exception:
                pass  # Тихо фейлим — память не критична для основной работы

        # Запускаем в фоне чтобы не блокировать ответ
        t = threading.Thread(target=_run, daemon=True)
        t.start()

    # ─── Форматирование для промпта ────────────────────────────────
    def format_for_prompt(self, memories: list) -> str:
        if not memories:
            return ""
        lines = "\n".join(f"• {m}" for m in memories)
        return (
            "=== ДОЛГОСРОЧНАЯ ПАМЯТЬ (факты о пользователе и прошлые задачи) ===\n"
            f"{lines}\n"
            "=== КОНЕЦ ПАМЯТИ ===\n\n"
            "Используй эти факты для персонализации ответа если они релевантны. "
            "Не упоминай память явно и не говори 'я помню что...'."
        )


