class Pipe:
    class Valves(BaseModel):
        MWS_API_KEY: str = Field(default="MWS_API_TOKEN")
        MWS_BASE_URL: str = Field(default="MWS_API_BASE")

        # Модели
        ROUTER_MODEL: str = Field(default="gemma-3-27b-it")
        TEXT_MODEL: str = Field(default="Qwen3-235B-A22B-Instruct-2507-FP8")
        VISION_MODEL: str = Field(default="qwen2.5-vl-72b")
        CODE_MODEL: str = Field(default="qwen3-coder-480b-a35b")
        SEARCH_MODEL: str = Field(default="llama-3.3-70b-instruct")
        IMAGE_MODEL: str = Field(default="qwen-image-lightning")

        SEARXNG_URL: str = Field(
            default="http://gpthub-searxng:8080/search?q={query}&format=json"
        )

        # Память — можно отключить через Valves если нужно
        MEMORY_ENABLED: bool = Field(default=True)

    def __init__(self):
        self.type = "pipe"
        self.id = "gpthub_ultimate_conveyor_v6_fixed"
        self.name = "GPTHub Ultimate Router v6.1 (Cleaned) 🚀"

    def _fetch_web_page(self, url: str) -> str:
        try:
            res = requests.get(
                url,
                headers={"User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)"},
                timeout=10,
            )
            if BeautifulSoup:
                soup = BeautifulSoup(res.text, "html.parser")
                for script in soup(["script", "style"]):
                    script.extract()
                return soup.get_text(separator=" ", strip=True)[:8000]
            else:
                text = re.sub(
                    r"<style.*?</style>", "", res.text, flags=re.DOTALL | re.IGNORECASE
                )
                text = re.sub(
                    r"<script.*?</script>", "", text, flags=re.DOTALL | re.IGNORECASE
                )
                text = re.sub(r"<[^>]+>", " ", text)
                return " ".join(text.split())[:8000]
        except Exception as e:
            return f"[Ошибка парсинга {url}: {str(e)}]"

    def _get_currency_rate(self, query: str) -> str:
        currency_map = {
            "доллар": "USD",
            "dollar": "USD",
            "usd": "USD",
            "$": "USD",
            "евро": "EUR",
            "euro": "EUR",
            "eur": "EUR",
            "€": "EUR",
            "юань": "CNY",
            "yuan": "CNY",
            "cny": "CNY",
            "фунт": "GBP",
            "pound": "GBP",
            "gbp": "GBP",
            "иена": "JPY",
            "yen": "JPY",
            "jpy": "JPY",
        }
        query_lower = query.lower()
        found_currency = None
        for keyword, code in currency_map.items():
            if keyword in query_lower:
                found_currency = code
                break

        if found_currency:
            try:
                cbr_res = requests.get(
                    "https://www.cbr.ru/scripts/XML_daily.asp",
                    headers={"User-Agent": "Mozilla/5.0"},
                    timeout=8,
                )
                pattern = (
                    rf"<CharCode>{found_currency}</CharCode>.*?<Value>([\d,]+)</Value>"
                )
                match = re.search(pattern, cbr_res.text, re.DOTALL)
                if match:
                    rate = match.group(1).replace(",", ".")
                    return f"- Курс {found_currency}/RUB по данным ЦБ РФ: {rate} рублей"
            except Exception:
                pass

        return ""

    def _search_web(self, query: str, searxng_url_template: str = "") -> str:
        currency_keywords = [
            "курс",
            "доллар",
            "евро",
            "юань",
            "валют",
            "рубл",
            "exchange rate",
            "usd",
            "eur",
        ]
        if any(kw in query.lower() for kw in currency_keywords):
            cbr_result = self._get_currency_rate(query)
            if cbr_result:
                return cbr_result

        enhanced_query = self._enhance_search_query(query)

        if searxng_url_template:
            try:
                searxng_url = searxng_url_template.replace(
                    "{query}",
                    requests.utils.quote(enhanced_query),
                )
                searxng_res = requests.get(
                    searxng_url,
                    headers={"User-Agent": "Mozilla/5.0"},
                    timeout=10,
                )
                searxng_data = searxng_res.json()
                results = []
                for item in searxng_data.get("results", [])[:5]:
                    title = item.get("title", "")
                    content = item.get("content", "")
                    if content:
                        results.append(
                            f"- {title}: {content}" if title else f"- {content}"
                        )
                    elif title:
                        results.append(f"- {title}")
                if results:
                    return "\n".join(results)
            except Exception:
                pass

        try:
            ia_url = f"https://api.duckduckgo.com/?q={requests.utils.quote(query)}&format=json&no_redirect=1&no_html=1&skip_disambig=1"
            ia_res = requests.get(
                ia_url, headers={"User-Agent": "Mozilla/5.0"}, timeout=8
            )
            ia_data = ia_res.json()

            ia_results = []
            if ia_data.get("AbstractText"):
                ia_results.append(ia_data["AbstractText"])
            if ia_data.get("Answer"):
                ia_results.append(f"Ответ: {ia_data['Answer']}")
            for topic in ia_data.get("RelatedTopics", [])[:3]:
                if isinstance(topic, dict) and topic.get("Text"):
                    ia_results.append(topic["Text"])

            if ia_results:
                return "\n".join([f"- {r}" for r in ia_results])
        except Exception:
            pass

        return "[Ничего не найдено. Возможно, стоит уточнить запрос.]"

    def _clean_junk(self, text: str) -> str:
        if not text:
            return ""
        text = re.sub(r"<(context|source)(?:\s[^>]*)?>([\s\S]*?)</\1>", r"\2", text)
        text = re.sub(r"</?(context|source)[^>]*>", "", text)

        if "### Task:" in text:
            if "Output:" in text:
                text = text.split("Output:")[-1]
            else:
                text = re.sub(
                    r"### Task:[\s\S]*?(incorporating inline citations|\[id\])[^\n]*\n",
                    "",
                    text,
                    flags=re.IGNORECASE,
                )

        text = text.replace("*### Task:", "").replace("*...", "")
        return text.strip()

    def _safe_json_load(self, raw: str) -> dict:
        raw = raw.strip()
        raw = re.sub(r"^```json\s*", "", raw, flags=re.IGNORECASE)
        raw = re.sub(r"```\s*$", "", raw, flags=re.IGNORECASE)
        raw = raw.strip()
        try:
            return json.loads(raw)
        except json.JSONDecodeError:
            raw = re.sub(r"}\s*{", "},{", raw)
            raw = re.sub(r"\]\s*\[", "],[", raw)
            try:
                return json.loads(raw)
            except:
                return {
                    "error": "Не удалось распарсить JSON от модели. Попробуй перефразировать запрос."
                }

    def _enhance_search_query(self, query: str) -> str:
        q = query.strip()
        q_lower = q.lower()

        corrections = {
            "арсенал": "Арсенал Лондон ФК Премьер-лига Англия",
            "реал": "Реал Мадрид",
            "спартак": "Спартак Москва",
            "зенит": "Зенит Санкт-Петербург",
            "динамо": "Динамо Москва",
            "цска": "ЦСКА Москва",
            "барса": "Барселона",
            "ман сити": "Манчестер Сити",
            "манчестер": "Манчестер Сити",
            "новости": "последние новости",
            "что происходит": "актуальные новости сегодня",
            "последние события": "последние новости",
            "сейчас в мире": "актуальные новости",
        }

        for key, replacement in corrections.items():
            if key in q_lower and replacement not in q_lower:
                q = q.replace(key, replacement, 1)
                break

        if any(
            word in q_lower
            for word in [
                "матч",
                "ближайшие",
                "расписание",
                "счёт",
                "результат",
                "когда",
            ]
        ):
            q += " (актуальное расписание или результаты)"

        return q

    def _get_text(self, content) -> str:
        if isinstance(content, str):
            return content
        if isinstance(content, list):
            return " ".join(
                [i.get("text", "") for i in content if i.get("type") == "text"]
            )
        return ""

    def _ask_vision_internally(self, valves, messages, system_instruction):
        headers = {
            "Authorization": f"Bearer {valves.MWS_API_KEY}",
            "Content-Type": "application/json",
        }
        last_msg_content = messages[-1]["content"]
        payload_messages = messages[:-1] + [
            {"role": "user", "content": last_msg_content}
        ]

        payload = {
            "model": valves.VISION_MODEL,
            "messages": payload_messages,
            "temperature": 0.2,
        }

        if isinstance(payload["messages"][-1]["content"], list):
            for item in payload["messages"][-1]["content"]:
                if item["type"] == "text":
                    item["text"] = system_instruction

        try:
            res = requests.post(
                f"{valves.MWS_BASE_URL}/chat/completions",
                headers=headers,
                json=payload,
                timeout=60,
            )
            return res.json()["choices"][0]["message"]["content"]
        except:
            return ""

